     1→"use client";
     2→
     3→import React, {
     4→  useCallback,
     5→  useEffect,
     6→  useMemo,
     7→  useRef,
     8→  useState,
     9→} from "react";
    10→
    11→interface FlickeringGridProps {
    12→  squareSize?: number;
    13→  gridGap?: number;
    14→  flickerChance?: number;
    15→  color?: string;
    16→  width?: number;
    17→  height?: number;
    18→  className?: string;
    19→
    20→  maxOpacity?: number;
    21→}
    22→
    23→const FlickeringGrid: React.FC<FlickeringGridProps> = ({
    24→  squareSize = 4,
    25→  gridGap = 6,
    26→  flickerChance = 0.3,
    27→  color = "rgb(0, 0, 0)",
    28→  width,
    29→  height,
    30→  className,
    31→  maxOpacity = 0.3,
    32→}) => {
    33→  const canvasRef = useRef<HTMLCanvasElement>(null);
    34→  const containerRef = useRef<HTMLDivElement>(null);
    35→  const [isInView, setIsInView] = useState(false);
    36→  const [canvasSize, setCanvasSize] = useState({ width: 0, height: 0 });
    37→
    38→  const memoizedColor = useMemo(() => {
    39→    const toRGBA = (color: string) => {
    40→      if (typeof window === "undefined") {
    41→        return `rgba(0, 0, 0,`;
    42→      }
    43→      const canvas = document.createElement("canvas");
    44→      canvas.width = canvas.height = 1;
    45→      const ctx = canvas.getContext("2d");
    46→      if (!ctx) return "rgba(255, 0, 0,";
    47→      ctx.fillStyle = color;
    48→      ctx.fillRect(0, 0, 1, 1);
    49→      const [r, g, b] = Array.from(ctx.getImageData(0, 0, 1, 1).data);
    50→      return `rgba(${r}, ${g}, ${b},`;
    51→    };
    52→    return toRGBA(color);
    53→  }, [color]);
    54→
    55→  const setupCanvas = useCallback(
    56→    (canvas: HTMLCanvasElement, width: number, height: number) => {
    57→      const dpr = window.devicePixelRatio || 1;
    58→      canvas.width = width * dpr;
    59→      canvas.height = height * dpr;
    60→      canvas.style.width = `${width}px`;
    61→      canvas.style.height = `${height}px`;
    62→      const cols = Math.floor(width / (squareSize + gridGap));
    63→      const rows = Math.floor(height / (squareSize + gridGap));
    64→
    65→      const squares = new Float32Array(cols * rows);
    66→      for (let i = 0; i < squares.length; i++) {
    67→        squares[i] = Math.random() * maxOpacity;
    68→      }
    69→
    70→      return { cols, rows, squares, dpr };
    71→    },
    72→    [squareSize, gridGap, maxOpacity]
    73→  );
    74→
    75→  const updateSquares = useCallback(
    76→    (squares: Float32Array, deltaTime: number) => {
    77→      for (let i = 0; i < squares.length; i++) {
    78→        if (Math.random() < flickerChance * deltaTime) {
    79→          squares[i] = Math.random() * maxOpacity;
    80→        }
    81→      }
    82→    },
    83→    [flickerChance, maxOpacity]
    84→  );
    85→
    86→  const drawGrid = useCallback(
    87→    (
    88→      ctx: CanvasRenderingContext2D,
    89→      width: number,
    90→      height: number,
    91→      cols: number,
    92→      rows: number,
    93→      squares: Float32Array,
    94→      dpr: number
    95→    ) => {
    96→      ctx.clearRect(0, 0, width, height);
    97→      ctx.fillStyle = "transparent";
    98→      ctx.fillRect(0, 0, width, height);
    99→
   100→      for (let i = 0; i < cols; i++) {
   101→        for (let j = 0; j < rows; j++) {
   102→          const opacity = squares[i * rows + j];
   103→          ctx.fillStyle = `${memoizedColor}${opacity})`;
   104→          ctx.fillRect(
   105→            i * (squareSize + gridGap) * dpr,
   106→            j * (squareSize + gridGap) * dpr,
   107→            squareSize * dpr,
   108→            squareSize * dpr
   109→          );
   110→        }
   111→      }
   112→    },
   113→    [memoizedColor, squareSize, gridGap]
   114→  );
   115→
   116→  useEffect(() => {
   117→    const canvas = canvasRef.current;
   118→    const container = containerRef.current;
   119→    if (!canvas || !container) return;
   120→
   121→    const ctx = canvas.getContext("2d");
   122→    if (!ctx) return;
   123→
   124→    let animationFrameId: number;
   125→    let gridParams: ReturnType<typeof setupCanvas>;
   126→
   127→    const updateCanvasSize = () => {
   128→      const newWidth = width || container.clientWidth;
   129→      const newHeight = height || container.clientHeight;
   130→      setCanvasSize({ width: newWidth, height: newHeight });
   131→      gridParams = setupCanvas(canvas, newWidth, newHeight);
   132→    };
   133→
   134→    updateCanvasSize();
   135→
   136→    let lastTime = 0;
   137→    const animate = (time: number) => {
   138→      if (!isInView) return;
   139→
   140→      const deltaTime = (time - lastTime) / 1000;
   141→      lastTime = time;
